  function approachTopAndLeft(top, left, fromRatio = 1, targetRatio = 1) {
    let sumTop = 0, sumLeft = 0;
    const rowsize = store_default.flowdata.length;
    const colsize = store_default.flowdata.length > 0 ? store_default.flowdata[0].length : 0;
    let row = 0, rowDiff = 0, col = 0, colDiff = 0;
    const rowsPos = [0, ...store_default.visibledatarow];
    const colsPos = [0, ...store_default.visibledatacolumn];
    for (let i = 0; i < rowsPos.length; i++) {
      if (rowsPos[i] <= top) {
        row = i;
        rowDiff = top - rowsPos[i];
      } else {
        break;
      }
    }
    for (let i = 0; i < colsPos.length; i++) {
      if (colsPos[i] <= left) {
        col = i;
        colDiff = left - colsPos[i];
      } else {
        break;
      }
    }
    rowDiff = Number((targetRatio * rowDiff / fromRatio).toFixed(2));
    colDiff = Number((targetRatio * colDiff / fromRatio).toFixed(2));
    for (let i = 0; i < rowsize && i < row; i++) {
      let rowlen = store_default.defaultrowlen;
      if (store_default.config["rowlen"] != null && store_default.config["rowlen"][i] != null) {
        rowlen = store_default.config["rowlen"][i];
      }
      const newRow = Math.round((rowlen + 1) * targetRatio);
      sumTop += newRow;
    }
    sumTop += rowDiff;
    for (let i = 0; i < colsize && i < col; i++) {
      let firstcolumnlen = store_default.defaultcollen;
      if (store_default.config["columnlen"] != null && store_default.config["columnlen"][i] != null) {
        firstcolumnlen = store_default.config["columnlen"][i];
      } else if (store_default.flowdata[0][i] != null && firstcolumnlen > 300) {
        firstcolumnlen = 300;
      }
      const newCol = Math.round((firstcolumnlen + 1) * targetRatio);
      sumLeft += newCol;
    }
    sumLeft += colDiff;
    return {
      left: Number(sumLeft.toFixed(2)),
      top: Number(sumTop.toFixed(2))
    };
  }
