  function selectTitlesMap(rangeMap, range1, range2) {
    let map = $.extend(true, {}, rangeMap);
    for (let i = range1; i <= range2; i++) {
      if (i in map) {
        continue;
      }
      map[i] = 0;
    }
    return map;
  }
  function selectTitlesRange(map) {
    let mapArr = [];
    for (let i in map) {
      mapArr.push(i);
    }
    mapArr.sort(function(a, b) {
      return a - b;
    });
    let rangeArr = [];
    let item = [];
    if (mapArr.length > 1) {
      for (let j = 1; j < mapArr.length; j++) {
        if (mapArr[j] - mapArr[j - 1] == 1) {
          item.push(mapArr[j - 1]);
          if (j == mapArr.length - 1) {
            item.push(mapArr[j]);
            rangeArr.push(item);
          }
        } else {
          if (j == 1) {
            if (j == mapArr.length - 1) {
              item.push(mapArr[j - 1]);
              rangeArr.push(item);
              rangeArr.push([mapArr[j]]);
            } else {
              rangeArr.push(mapArr[0]);
            }
          } else if (j == mapArr.length - 1) {
            item.push(mapArr[j - 1]);
            rangeArr.push(item);
            rangeArr.push([mapArr[j]]);
          } else {
            item.push(mapArr[j - 1]);
            rangeArr.push(item);
            item = [];
          }
        }
      }
    } else {
      rangeArr.push([mapArr[0]]);
    }
    return rangeArr;
  }
  function selectIsOverlap(range) {
    if (range == null) {
      range = store_default.luckysheet_select_save;
    }
    range = JSON.parse(JSON.stringify(range));
    let overlap = false;
    let map = {};
    for (let s = 0; s < range.length; s++) {
      let str_r = range[s].row[0], end_r = range[s].row[1];
      let str_c = range[s].column[0], end_c = range[s].column[1];
      for (let r = str_r; r <= end_r; r++) {
        for (let c = str_c; c <= end_c; c++) {
          if (r + "_" + c in map) {
            overlap = true;
            break;
          } else {
            map[r + "_" + c] = 0;
          }
        }
      }
    }
    return overlap;
  }
