  function rowHasMerge(r, c1, c2) {
    let rowHasMerge2 = false;
    for (let c = c1; c <= c2; c++) {
      let cell = store_default.flowdata[r][c];
      if (getObjType(cell) == "object" && "mc" in cell) {
        rowHasMerge2 = true;
        break;
      }
    }
    return rowHasMerge2;
  }
  function colHasMerge(c, r1, r2) {
    let colHasMerge2 = false;
    for (let r = r1; r <= r2; r++) {
      let cell = store_default.flowdata[r][c];
      if (getObjType(cell) == "object" && "mc" in cell) {
        colHasMerge2 = true;
        break;
      }
    }
    return colHasMerge2;
  }
  function getRowMerge(rIndex, c1, c2) {
    let r1 = 0, r2 = store_default.flowdata.length - 1;
    let str = null;
    if (rIndex > r1) {
      for (let r = rIndex; r >= r1; r--) {
        for (let c = c1; c <= c2; c++) {
          let cell = store_default.flowdata[r][c];
          if (getObjType(cell) == "object" && "mc" in cell) {
            let mc = store_default.config["merge"][cell["mc"].r + "_" + cell["mc"].c];
            if (str == null || mc.r < str) {
              str = mc.r;
            }
          }
        }
        if (rowHasMerge(str - 1, c1, c2) && str > r1) {
          r = str - 1;
        } else {
          break;
        }
      }
    } else {
      str = r1;
    }
    let end = null;
    if (rIndex < r2) {
      for (let r = rIndex; r <= r2; r++) {
        for (let c = c1; c <= c2; c++) {
          let cell = store_default.flowdata[r][c];
          if (getObjType(cell) == "object" && "mc" in cell) {
            let mc = store_default.config["merge"][cell["mc"].r + "_" + cell["mc"].c];
            if (end == null || mc.r + mc.rs - 1 > end) {
              end = mc.r + mc.rs - 1;
            }
          }
        }
        if (rowHasMerge(end + 1, c1, c2) && end < r2) {
          r = end + 1;
        } else {
          break;
        }
      }
    } else {
      end = r2;
    }
    return [str, end];
  }
